script:
// ==============================
// Salary Annexure – Client Script
// ==============================

frappe.ui.form.on("Salary Annexure", {

    refresh(frm) {
        // Salary totals
        calculate_salary_totals(frm);
    },

    // 🔹 Salary Component Template
    custom_salary_component_template(frm) {
        if (!frm.doc.custom_salary_component_template) return;

        frappe.call({
            method: "frappe.client.get",
            args: {
                doctype: "Salary Component Template",
                name: frm.doc.custom_salary_component_template
            },
            callback(r) {
                if (!r.message) return;

                frm.clear_table("salary_components");

                r.message.template_components.forEach(t => {
                    let row = frm.add_child("salary_components");
                    row.salary_component = t.salary_component;
                    row.section = t.section;
                    row.monthly = 0;
                    row.annualized = 0;
                });

                frm.refresh_field("salary_components");
            }
        });
    },

    // 🔹 Condition Template (IMPORTANT)
  custom_condition_template(frm) {
    if (!frm.doc.custom_condition_template) return;

    frappe.call({
        method: "frappe.client.get",
        args: {
            doctype: "Salary Annexure Condition Template",
            name: frm.doc.custom_condition_template
        },
        callback(r) {
            if (!r.message) return;

            // Double check if the field exists before proceeding
            if (!frm.get_field("custom_terms_and_condtions")) {
                frappe.msgprint(__("Field 'custom_terms_and_condtions' not found in this Doctype."));
                return;
            }

            frm.clear_table("custom_terms_and_condtions");

            r.message.conditions.forEach(c => {
                let row = frm.add_child("custom_terms_and_condtions");
                // Ensure these fieldnames match the CHILD DOCTYPE fields
                row.condition_text = c.condition_text; 
                row.show = c.show;
            });

            frm.refresh_field("custom_terms_and_condtions");
        }
    });
}
});


// 🔹 Salary Component Child Table Logic
frappe.ui.form.on("Salary Annexure Component", {

    monthly(frm, cdt, cdn) {
        let row = locals[cdt][cdn];
        row.annualized = (row.monthly || 0) * 12;

        frm.refresh_field("salary_components");
        calculate_salary_totals(frm);
    },

    section(frm) {
        calculate_salary_totals(frm);
    }
});


// 🔹 Total Calculation
function calculate_salary_totals(frm) {
    let a_monthly = 0, a_annual = 0;
    let b_monthly = 0, b_annual = 0;

    (frm.doc.salary_components || []).forEach(row => {
        if (row.section === "A") {
            a_monthly += row.monthly || 0;
            a_annual += row.annualized || 0;
        }
        if (row.section === "B") {
            b_monthly += row.monthly || 0;
            b_annual += row.annualized || 0;
        }
    });

    frm.set_value("subtotal_a_monthly", a_monthly);
    frm.set_value("subtotal_a_annual", a_annual);
    frm.set_value("subtotal_b_monthly", b_monthly);
    frm.set_value("subtotal_b_annual", b_annual);
    frm.set_value("total_monthly", a_monthly + b_monthly);
    frm.set_value("total_annual", a_annual + b_annual);
}

frappe.ui.form.on("Job Offer", {

    refresh(frm) {
        set_annexure_logic(frm);
    },

    job_applicant(frm) {
        frm.set_value("custom_salary_annexure", null);
        set_annexure_logic(frm);
    }
});

function set_annexure_logic(frm) {
    if (!frm.doc.job_applicant) return;

    // Filter annexure dropdown
    frm.set_query("custom_salary_annexure", () => {
        return {
            filters: {
                custom_job_applicant: frm.doc.job_applicant
            }
        };
    });

    // Auto-select latest annexure
    frappe.call({
        method: "frappe.client.get_list",
        args: {
            doctype: "Salary Annexure",
            filters: {
                custom_job_applicant: frm.doc.job_applicant
            },
            fields: ["name"],
            order_by: "creation desc",
            limit_page_length: 1
        },
        callback(r) {
            if (r.message && r.message.length) {
                frm.set_value("custom_salary_annexure", r.message[0].name);
            }
        }
    });
}

frappe.ui.form.on('Job Opening', {
    refresh(frm) {
        // Purana button clear karein aur naya single button add karein
        frm.remove_custom_button("Parse CV and Score");
        
        frm.add_custom_button(__("Parse CV and Score"), () => {
            new frappe.ui.FileUploader({
                allow_multiple: false,
                on_success(file) {
                    // 1. PDF Upload record create karne ke liye pehla call
                    frappe.call({
                        method: "resume.resume.upload.save_cv_to_pdf_upload",
                        args: {
                            file_url: file.file_url,
                            job_id: frm.doc.name,
                            designation: frm.doc.designation,
                            action: "Score" // Hamesha Score pass hoga
                        },
                        freeze: true,
                        freeze_message: __("Saving CV and Creating PDF Upload..."),
                        callback(r) {
                            if (!r.message) return;

                            frappe.show_alert({
                                message: __("CV saved. Starting parsing and scoring..."),
                                indicator: 'green'
                            });

                            // 2. Job Applicant create aur scoring start karne ke liye dusra call
                            frappe.call({
                                method: "resume.resume.doctype.pdf_upload.pdf_upload.process_pdfs",
                                args: {
                                    docname: r.message // r.message me naya PDF Upload name milega
                                },
                                freeze: true,
                                freeze_message: __("Creating Job Applicant & Scoring..."),
                                callback() {
                                    frappe.show_alert({
                                        message: __("Job Applicant creation and processing started"),
                                        indicator: 'blue'
                                    });
                                    frm.reload_doc(); // Screen refresh taaki changes dikhe
                                }
                            });
                        }
                    });
                }
            });
        });
    }
});
